#include <stdio.h>
#include <stdbool.h>

/*
 * Gate-Level Implementation of 4-to-1 Multiplexer
 * 
 * Logic: Y = S1'S0'I0 + S1'S0I1 + S1S0'I2 + S1S0I3
 * 
 * Circuit Structure:
 * - 2 NOT gates for S1' and S0'
 * - 4 AND gates for each product term
 * - 1 OR gate to combine all terms
 */

// Basic gate functions
bool NOT(bool a) {
 return !a;
}

bool AND(bool a, bool b) {
 return a && b;
}

bool OR(bool a, bool b) {
 return a || b;
}

/*
 * 4-to-1 Multiplexer using gate-level logic
 * Inputs: I0, I1, I2, I3 (data lines)
 * S0, S1 (selection lines)
 * Output: Y (selected data)
 */
bool mux_4to1_gate_level(bool I0, bool I1, bool I2, bool I3, 
 bool S0, bool S1) {
 // Step 1: Generate complements of selection lines (NOT gates)
 bool S0_not = NOT(S0);
 bool S1_not = NOT(S1);

 // Step 2: Generate all four product terms (AND gates)
 // Term 0: S1' * S0' * I0
 bool term0 = AND(AND(S1_not, S0_not), I0);

 // Term 1: S1' * S0 * I1
 bool term1 = AND(AND(S1_not, S0), I1);

 // Term 2: S1 * S0' * I2
 bool term2 = AND(AND(S1, S0_not), I2);

 // Term 3: S1 * S0 * I3
 bool term3 = AND(AND(S1, S0), I3);

 // Step 3: Combine all terms (OR gate)
 bool Y = OR(OR(term0, term1), OR(term2, term3));

 return Y;
}

/*
 * Simplified 4-to-1 MUX using array indexing
 */
bool mux_4to1_index(bool inputs[], bool S0, bool S1) {
 // Convert selection bits to index (0-3)
 int index = (S1 * 2) + S0;
 return inputs[index];
}

/*
 * Cascaded 8-to-1 MUX using two 4-to-1 MUXes and one 2-to-1 MUX
 * This demonstrates how larger MUXes are built from smaller ones
 */
bool mux_8to1_cascaded(bool I0, bool I1, bool I2, bool I3,
 bool I4, bool I5, bool I6, bool I7,
 bool S0, bool S1, bool S2) {
 // First stage: Two 4-to-1 MUXes
 // MUX A: selects from I0-I3 based on S0, S1
 bool mux_a = mux_4to1_gate_level(I0, I1, I2, I3, S0, S1);

 // MUX B: selects from I4-I7 based on S0, S1
 bool mux_b = mux_4to1_gate_level(I4, I5, I6, I7, S0, S1);

 // Second stage: 2-to-1 MUX selects between mux_a and mux_b
 // based on S2
 bool Y = mux_4to1_gate_level(mux_a, mux_b, 0, 0, S2, 0);

 return Y;
}

int main() {
 printf("========================================\n");
 printf("GATE-LEVEL 4-TO-1 MULTIPLEXER\n");
 printf("========================================\n\n");

 // Test all 4 selection combinations
 bool inputs[] = {0, 1, 1, 0}; // I0=0, I1=1, I2=1, I3=0

 printf("Inputs: I0=%d, I1=%d, I2=%d, I3=%d\n\n", 
 inputs[0], inputs[1], inputs[2], inputs[3]);

 printf("S1 S0 | Selected Input | Output Y\n");
 printf("------|-----------------|----------\n");

 for (int S1 = 0; S1 <= 1; S1++) {
 for (int S0 = 0; S0 <= 1; S0++) {
 int idx = S1 * 2 + S0;
 bool Y = mux_4to1_gate_level(
 inputs[0], inputs[1], inputs[2], inputs[3], S0, S1);
 printf(" %d %d | I%d | %d\n", S1, S0, idx, Y);
 }
 }

 printf("\n========================================\n");
 printf("CASCADED 8-TO-1 MULTIPLEXER\n");
 printf("========================================\n\n");

 // Test 8:1 cascaded MUX
 bool inputs_8[] = {1, 0, 1, 0, 1, 0, 1, 0};
 printf("Testing 8:1 MUX with alternating inputs:\n");

 for (int S2 = 0; S2 <= 1; S2++) {
 for (int S1 = 0; S1 <= 1; S1++) {
 for (int S0 = 0; S0 <= 1; S0++) {
 bool Y = mux_8to1_cascaded(
 inputs_8[0], inputs_8[1], inputs_8[2], inputs_8[3],
 inputs_8[4], inputs_8[5], inputs_8[6], inputs_8[7],
 S0, S1, S2);
 int idx = S2*4 + S1*2 + S0;
 printf("S2=%d S1=%d S0=%d -> Selected I%d, Y=%d\n", 
 S2, S1, S0, idx, Y);
 }
 }
 }

 return 0;
}
